@app.get("/health")
def health():
    ok = True
    details = {"memcached": "unknown"}
    try:
        client = get_memcache_client()
        test_key = "healthcheck:ping"
        client.set(test_key, "1", expire=2)
        v = client.get(test_key)
        ok = v is not None
        details["memcached"] = "ok" if ok else "unreachable"
    except MemcacheError:
        ok = False
        details["memcached"] = "error"
    except Exception:
        ok = False
        details["memcached"] = "error"
    return jsonify({"ok": ok, "details": details}), (200 if ok else 503)


